from __future__ import annotations
from dataclasses import dataclass, asdict

@dataclass(frozen=True)
class ToolSpec:
    id: str
    title: str
    domain: str
    topic: str
    family: str
    engine: str
    description: str
    inputs: list[dict]
    graph_types: list[str]
    audience_modes: list[str]
    safety_level: str = "educational"


def input_field(name, label, kind="text", default="", help="", options=None):
    out = {"name": name, "label": label, "type": kind, "default": default, "help": help}
    if options:
        out["options"] = options
    return out

