TOOL_BY_ID = {t.id: t for t in TOOLS}

def list_tools(domain: str | None = None, topic: str | None = None, limit: int | None = None) -> list[dict]:
    items = TOOLS
    if domain:
        d = domain.lower()
        items = [t for t in items if d in t.domain.lower()]
    if topic:
        q = topic.lower().replace('-', ' ')
        items = [t for t in items if q in (t.topic + ' ' + t.domain + ' ' + t.description + ' ' + t.family).lower()]
    data = [asdict(t) for t in items]
    if limit:
        data = data[:limit]
    return data

def get_tool(tool_id: str) -> dict | None:
    t = TOOL_BY_ID.get(tool_id)
    return asdict(t) if t else None

def search_tools(query: str, limit: int = 6) -> list[dict]:
    q = (query or '').lower()
    scored = []
    for t in TOOLS:
        blob = ' '.join([t.id, t.title, t.domain, t.topic, t.family, t.description, ' '.join(t.graph_types)]).lower()
        score = sum(2 if token in t.title.lower() else 1 for token in q.split() if token in blob)
        if score:
            scored.append((score, t))
    scored.sort(key=lambda x: (-x[0], x[1].title))
    return [asdict(t) for _, t in scored[:limit]] or [asdict(t) for t in TOOLS[:limit]]
